mapper.select:
select * from `student_academic`

     and id = #{id}
     and student_id = #{studentId}
     and gpa_color = #{gpaColor}

order by id desc

mapper.update:
update `student_academic`
student_id = #{studentId}, total_credit = #{totalCredit}, earned_credit = #{earnedCredit}, gpa = #{gpa}, gpa_color = #{gpaColor}, risk_note = #{riskNote}, update_time = #{updateTime},
where id = #{id}
